const _ = require('lodash');
const problemsData = require('../../data/problems.json');

/**
 * Filters problems based on provided filters: difficulty, tags.
 * @param {Array} problems
 * @param {Object} filters
 * @returns {Array}
 */
function filterProblems(problems, filters) {
  return problems.filter(problem => {
    if (filters.difficulty && problem.difficulty !== filters.difficulty) {
      return false;
    }
    if (filters.tags && filters.tags.length > 0) {
      if (!problem.tags || !filters.tags.every(tag => problem.tags.includes(tag))) {
        return false;
      }
    }
    return true;
  });
}

/**
 * Computes totals for component languages and statuses from a list of problems.
 * @param {Array} problems
 * @returns {Object} { componentLanguageTotals: {}, componentStatusTotals: {} }
 */
function computeComponentTotals(problems) {
  const componentLanguageTotals = {};
  const componentStatusTotals = {};

  problems.forEach(problem => {
    if (problem.components && Array.isArray(problem.components)) {
      problem.components.forEach(component => {
        if (component.language) {
          componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
        }
        if (component.status) {
          componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
        }
      });
    }
  });

  return { componentLanguageTotals, componentStatusTotals };
}

/**
 * Lists problems with optional filters and metadata including component totals.
 * @param {Object} params
 * @param {boolean} params.includeComponents - whether to include component totals metadata
 * @param {number} params.limit - max number of problems to return
 * @param {string} params.difficulty - filter by difficulty
 * @param {Array<string>} params.tags - filter by tags
 * @returns {Object} { problems: Array, metadata: Object }
 */
function listProblems(params) {
  const includeComponents = params.includeComponents === true;
  const limit = params.limit && Number.isInteger(params.limit) && params.limit > 0 ? params.limit : problemsData.length;
  const difficulty = params.difficulty || null;
  const tags = Array.isArray(params.tags) ? params.tags : [];

  // Filter problems
  let filteredProblems = filterProblems(problemsData, { difficulty, tags });

  // Limit problems
  filteredProblems = filteredProblems.slice(0, limit);

  const result = {
    problems: filteredProblems,
    metadata: {}
  };

  if (includeComponents) {
    const { componentLanguageTotals, componentStatusTotals } = computeComponentTotals(filteredProblems);
    result.metadata.componentLanguageTotals = componentLanguageTotals;
    result.metadata.componentStatusTotals = componentStatusTotals;
  }

  return result;
}

module.exports = {
  listProblems
};
